Rule.Source:
import sailpoint.api.*;
import sailpoint.object.*;

log.error("items in exclusion rule  :"+items);
log.error("itemsToExclude in exclusion rule  :"+itemsToExclude);
log.error("entity in exclusion rule  :"+entity );

Iterator it=items.iterator();


while(it!=null @and it.hasNext()){

  sailpoint.api.certification.DataOwnerCertificationBuilder.DataOwnerCertifiable certifiable=(sailpoint.api.certification.DataOwnerCertificationBuilder.DataOwnerCertifiable)it.next();
  Map map=new HashMap();
  log.error("certifiable object--"+certifiable);

  Entitlements ent=(Entitlements)certifiable.getEntitlements();

  log.error("entitlement object --"+ent);

  map=ent.getAttributes();

  log.error("attributes map --"+map);

  for(String key:map.keySet()){
    Filter filter=Filter.and(Filter.eq("value",map.get(key)),Filter.ne("owner",null));
    ManagedAttribute ma=context.getUniqueObject(ManagedAttribute.class,filter);

    log.error("managedAttribute ma --"+ma);
    if(ma==null){

      itemsToExclude.add(certifiable);
      //items.remove(certifiable);

    }
  }
}

items.removeAll(itemsToExclude);




return "mahesh";
